import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { createReport } from '../../services/api';

function NewReport() {
  const [form, setForm] = useState({
    description: '',
    report_type: 'vandalism',
    room: 'CL01',
    priority: 'Medium'
  });
  const [photo, setPhoto] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    const userStr = localStorage.getItem('user');
    if (!userStr) {
      navigate('/login');
      return;
    }
    
    const user = JSON.parse(userStr);
    setLoading(true);
    setError('');
    
    const formData = new FormData();
    formData.append('description', form.description);
    formData.append('report_type', form.report_type);
    formData.append('room', form.room);
    formData.append('priority', form.priority);
    formData.append('user_id', user.id);
    
    if (photo) formData.append('photo', photo);

    try {
      console.log('Submitting report...');
      const response = await createReport(formData);
      console.log('Success:', response.data);
      navigate('/dashboard');
    } catch (err) {
      console.error('Full error object:', err);
      console.error('Error response:', err.response);
      console.error('Error data:', err.response?.data);
      console.error('Error status:', err.response?.status);
      
      let errorMessage = 'Failed to create report';
      if (err.response?.data?.error) {
        errorMessage = err.response.data.error;
      } else if (err.response?.data) {
        errorMessage = JSON.stringify(err.response.data);
      } else if (err.message) {
        errorMessage = err.message;
      }
      
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return (
    <div style={{
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      minHeight: '100vh',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center'
    }}>
      <div style={{
        background: 'white',
        padding: '30px 50px',
        borderRadius: '12px',
        boxShadow: '0 20px 40px rgba(0,0,0,0.2)',
        color: '#0066ff',
        fontSize: '18px',
        fontWeight: '500'
      }}>
        <i className="bi bi-arrow-repeat" style={{ marginRight: '10px', animation: 'spin 1s infinite linear' }}></i>
        Creating report...
      </div>
      <style>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );

  return (
    <div style={{
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      minHeight: '100vh',
      padding: '40px 20px',
      position: 'relative'
    }}>
      {/* Background Pattern */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        opacity: 0.1,
        backgroundImage: 'radial-gradient(circle at 1px 1px, white 1px, transparent 0)',
        backgroundSize: '40px 40px',
        pointerEvents: 'none'
      }}></div>

      <div style={{ maxWidth: '600px', margin: '0 auto', position: 'relative' }}>
        {/* Header with enhanced styling */}
        <div style={{
          marginBottom: '30px',
          textAlign: 'center'
        }}>
          <h1 style={{
            color: 'white',
            fontSize: '36px',
            fontWeight: '700',
            margin: 0,
            textShadow: '0 2px 10px rgba(0,0,0,0.2)'
          }}>
            <i className="bi bi-plus-circle" style={{ marginRight: '15px' }}></i>
            Create Report
          </h1>
          <p style={{
            color: 'rgba(255,255,255,0.8)',
            fontSize: '16px',
            marginTop: '10px'
          }}>
            Submit a new issue or concern
          </p>
        </div>

        {/* Main Card with enhanced box shadow */}
        <div style={{
          background: 'white',
          borderRadius: '20px',
          boxShadow: '0 20px 40px rgba(0,0,0,0.2), 0 6px 12px rgba(0,0,0,0.1)',
          overflow: 'hidden',
          transition: 'transform 0.3s ease, box-shadow 0.3s ease',
          animation: 'fadeInUp 0.5s ease-out'
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.transform = 'translateY(-5px)';
          e.currentTarget.style.boxShadow = '0 30px 50px rgba(0,0,0,0.25), 0 10px 20px rgba(0,0,0,0.15)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = 'translateY(0)';
          e.currentTarget.style.boxShadow = '0 20px 40px rgba(0,0,0,0.2), 0 6px 12px rgba(0,0,0,0.1)';
        }}>
          {/* Card Header with gradient */}
          <div style={{
            padding: '20px 30px',
            background: 'linear-gradient(135deg, #0066ff 0%, #00c6ff 100%)',
            color: 'white',
            fontWeight: '600',
            fontSize: '18px',
            borderBottom: '1px solid rgba(255,255,255,0.1)'
          }}>
            <i className="bi bi-file-text" style={{ marginRight: '10px', fontSize: '20px' }}></i>
            Report Details
          </div>
          
          <div style={{ padding: '30px' }}>
            {error && (
              <div style={{
                background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
                color: '#ffffff',
                padding: '16px 20px',
                borderRadius: '12px',
                marginBottom: '25px',
                border: 'none',
                boxShadow: '0 10px 20px rgba(0,0,0,0.1)',
                display: 'flex',
                alignItems: 'center',
                gap: '10px',
                animation: 'slideDown 0.3s ease-out'
              }}>
                <i className="bi bi-exclamation-triangle-fill" style={{ fontSize: '20px' }}></i>
                {error}
              </div>
            )}

            <form onSubmit={handleSubmit}>
              {/* Type and Room in 2 columns */}
              <div style={{ 
                display: 'grid', 
                gridTemplateColumns: '1fr 1fr', 
                gap: '20px', 
                marginBottom: '25px' 
              }}>
                <div>
                  <label style={{ 
                    color: '#333', 
                    display: 'block', 
                    marginBottom: '8px', 
                    fontWeight: '600',
                    fontSize: '14px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px'
                  }}>
                    <i className="bi bi-tag" style={{ color: '#0066ff' }}></i>
                    Type
                  </label>
                  <select
                    value={form.report_type}
                    onChange={(e) => setForm({...form, report_type: e.target.value})}
                    style={{
                      width: '100%',
                      padding: '14px',
                      background: '#ffffff',
                      border: '2px solid #e0e0e0',
                      borderRadius: '12px',
                      color: '#333',
                      fontSize: '15px',
                      transition: 'all 0.2s',
                      outline: 'none',
                      cursor: 'pointer'
                    }}
                    onFocus={(e) => {
                      e.target.style.borderColor = '#0066ff';
                      e.target.style.boxShadow = '0 0 0 3px rgba(0,102,255,0.1)';
                    }}
                    onBlur={(e) => {
                      e.target.style.borderColor = '#e0e0e0';
                      e.target.style.boxShadow = 'none';
                    }}
                  >
                    <option value="vandalism">Vandalism</option>
                    <option value="waste">Waste</option>
                    <option value="technical">Technical</option>
                  </select>
                </div>
                
                <div>
                  <label style={{ 
                    color: '#333', 
                    display: 'block', 
                    marginBottom: '8px', 
                    fontWeight: '600',
                    fontSize: '14px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px'
                  }}>
                    <i className="bi bi-door-open" style={{ color: '#0066ff' }}></i>
                    Room
                  </label>
                  <select
                    value={form.room}
                    onChange={(e) => setForm({...form, room: e.target.value})}
                    style={{
                      width: '100%',
                      padding: '14px',
                      background: '#ffffff',
                      border: '2px solid #e0e0e0',
                      borderRadius: '12px',
                      color: '#333',
                      fontSize: '15px',
                      transition: 'all 0.2s',
                      outline: 'none',
                      cursor: 'pointer'
                    }}
                    onFocus={(e) => {
                      e.target.style.borderColor = '#0066ff';
                      e.target.style.boxShadow = '0 0 0 3px rgba(0,102,255,0.1)';
                    }}
                    onBlur={(e) => {
                      e.target.style.borderColor = '#e0e0e0';
                      e.target.style.boxShadow = 'none';
                    }}
                  >
                    <option value="CL01">CL01</option>
                    <option value="CL02">CL02</option>
                    <option value="CL03">CL03</option>
                    <option value="CL04">CL04</option>
                  </select>
                </div>
              </div>

              {/* Priority */}
              <div style={{ marginBottom: '25px' }}>
                <label style={{ 
                  color: '#333', 
                  display: 'block', 
                  marginBottom: '8px', 
                  fontWeight: '600',
                  fontSize: '14px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <i className="bi bi-flag" style={{ color: '#0066ff' }}></i>
                  Priority
                </label>
                <select
                  value={form.priority}
                  onChange={(e) => setForm({...form, priority: e.target.value})}
                  style={{
                    width: '100%',
                    padding: '14px',
                    background: '#ffffff',
                    border: '2px solid #e0e0e0',
                    borderRadius: '12px',
                    color: '#333',
                    fontSize: '15px',
                    transition: 'all 0.2s',
                    outline: 'none',
                    cursor: 'pointer'
                  }}
                  onFocus={(e) => {
                    e.target.style.borderColor = '#0066ff';
                    e.target.style.boxShadow = '0 0 0 3px rgba(0,102,255,0.1)';
                  }}
                  onBlur={(e) => {
                    e.target.style.borderColor = '#e0e0e0';
                    e.target.style.boxShadow = 'none';
                  }}
                >
                  <option value="Low">Low</option>
                  <option value="Medium">Medium</option>
                  <option value="High">High</option>
                </select>
              </div>

              {/* Description */}
              <div style={{ marginBottom: '25px' }}>
                <label style={{ 
                  color: '#333', 
                  display: 'block', 
                  marginBottom: '8px', 
                  fontWeight: '600',
                  fontSize: '14px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <i className="bi bi-chat-dots" style={{ color: '#0066ff' }}></i>
                  Description
                </label>
                <textarea
                  rows="4"
                  value={form.description}
                  onChange={(e) => setForm({...form, description: e.target.value})}
                  required
                  style={{
                    width: '100%',
                    padding: '14px',
                    background: '#ffffff',
                    border: '2px solid #e0e0e0',
                    borderRadius: '12px',
                    color: '#333',
                    fontSize: '15px',
                    resize: 'vertical',
                    transition: 'all 0.2s',
                    outline: 'none',
                    fontFamily: 'inherit'
                  }}
                  onFocus={(e) => {
                    e.target.style.borderColor = '#0066ff';
                    e.target.style.boxShadow = '0 0 0 3px rgba(0,102,255,0.1)';
                  }}
                  onBlur={(e) => {
                    e.target.style.borderColor = '#e0e0e0';
                    e.target.style.boxShadow = 'none';
                  }}
                />
              </div>

              {/* Photo Upload */}
              <div style={{ marginBottom: '35px' }}>
                <label style={{ 
                  color: '#333', 
                  display: 'block', 
                  marginBottom: '8px', 
                  fontWeight: '600',
                  fontSize: '14px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <i className="bi bi-camera" style={{ color: '#0066ff' }}></i>
                  Photo (optional)
                </label>
                <div style={{
                  border: '2px dashed #e0e0e0',
                  borderRadius: '12px',
                  padding: '20px',
                  textAlign: 'center',
                  background: '#f8f9fa',
                  transition: 'all 0.2s',
                  cursor: 'pointer'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.borderColor = '#0066ff';
                  e.currentTarget.style.background = '#f0f7ff';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.borderColor = '#e0e0e0';
                  e.currentTarget.style.background = '#f8f9fa';
                }}>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => setPhoto(e.target.files[0])}
                    style={{
                      width: '100%',
                      padding: '10px',
                      background: 'transparent',
                      border: 'none',
                      color: '#333',
                      fontSize: '14px',
                      cursor: 'pointer'
                    }}
                  />
                  <p style={{ color: '#999', fontSize: '13px', margin: '10px 0 0 0' }}>
                    <i className="bi bi-cloud-upload" style={{ marginRight: '5px' }}></i>
                    Click or drag to upload
                  </p>
                </div>
              </div>

              {/* Buttons */}
              <div style={{ display: 'flex', gap: '15px' }}>
                <button
                  type="submit"
                  disabled={loading}
                  style={{
                    flex: 1,
                    padding: '16px',
                    background: 'linear-gradient(135deg, #0066ff 0%, #00c6ff 100%)',
                    color: 'white',
                    border: 'none',
                    borderRadius: '12px',
                    fontWeight: '700',
                    fontSize: '16px',
                    cursor: loading ? 'not-allowed' : 'pointer',
                    opacity: loading ? 0.7 : 1,
                    transition: 'all 0.3s',
                    boxShadow: '0 10px 20px rgba(0,102,255,0.3)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '10px'
                  }}
                  onMouseEnter={(e) => {
                    if (!loading) {
                      e.target.style.transform = 'translateY(-2px)';
                      e.target.style.boxShadow = '0 15px 30px rgba(0,102,255,0.4)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (!loading) {
                      e.target.style.transform = 'translateY(0)';
                      e.target.style.boxShadow = '0 10px 20px rgba(0,102,255,0.3)';
                    }
                  }}
                >
                  {loading ? (
                    <>
                      <i className="bi bi-arrow-repeat" style={{ animation: 'spin 1s infinite linear' }}></i>
                      SUBMITTING...
                    </>
                  ) : (
                    <>
                      <i className="bi bi-check-lg"></i>
                      SUBMIT REPORT
                    </>
                  )}
                </button>
                
                <Link
                  to="/dashboard"
                  style={{
                    padding: '16px 30px',
                    background: '#f5f5f5',
                    color: '#666',
                    border: '2px solid #e0e0e0',
                    borderRadius: '12px',
                    textDecoration: 'none',
                    fontWeight: '600',
                    fontSize: '16px',
                    transition: 'all 0.3s',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px'
                  }}
                  onMouseEnter={(e) => {
                    e.target.style.background = '#e8e8e8';
                    e.target.style.borderColor = '#0066ff';
                    e.target.style.color = '#0066ff';
                    e.target.style.transform = 'translateY(-2px)';
                    e.target.style.boxShadow = '0 10px 20px rgba(0,0,0,0.1)';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.background = '#f5f5f5';
                    e.target.style.borderColor = '#e0e0e0';
                    e.target.style.color = '#666';
                    e.target.style.transform = 'translateY(0)';
                    e.target.style.boxShadow = 'none';
                  }}
                >
                  <i className="bi bi-x-lg"></i>
                  Cancel
                </Link>
              </div>
            </form>
          </div>
        </div>
      </div>

      {/* Animation keyframes */}
      <style>
        {`
          @keyframes spin {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
          }
          
          @keyframes slideDown {
            from {
              opacity: 0;
              transform: translateY(-20px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
          
          @keyframes fadeInUp {
            from {
              opacity: 0;
              transform: translateY(30px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
        `}
      </style>
    </div>
  );
}

export default NewReport;
